import{_ as t,o as i,c as a,an as o}from"./chunks/framework.D5fFzH9V.js";const m=JSON.parse('{"title":"BIMI: Email Branding (and Why Some Clients Don’t Show It)","description":"How BIMI works, what your SVG must look like, and how to publish it via DNS (with optional mark certificates).","frontmatter":{"pageClass":"blog-page","title":"BIMI: Email Branding (and Why Some Clients Don’t Show It)","author":"Samuel Haim","description":"How BIMI works, what your SVG must look like, and how to publish it via DNS (with optional mark certificates).","tags":"email,dns,security,anti-phishing","date":"2026-03-20T00:00:00.000Z","cover":"/images/bimi-email-branding-cover.png"},"headers":[],"relativePath":"blog/bimi-email-branding.md","filePath":"blog/bimi-email-branding.md"}'),r={name:"blog/bimi-email-branding.md"};function s(n,e,l,d,c,h){return i(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="bimi-email-branding-and-why-some-clients-don-t-show-it" tabindex="-1">BIMI: Email Branding (and Why Some Clients Don’t Show It) <a class="header-anchor" href="#bimi-email-branding-and-why-some-clients-don-t-show-it" aria-label="Permalink to &quot;BIMI: Email Branding (and Why Some Clients Don’t Show It)&quot;">​</a></h1><p>BIMI (Brand Indicators for Message Identification) is used to display brand logos in email clients. This should make it easier to distinguish between legitimate emails and phishing attempts.</p><p>However, some email clients (and by extension, email providers) require a mark certificate before such an image is shown. Others <em>only</em> require DMARC enforcement. There are two certificate types, which can be used for BIMI. Both of these certificates have their pros and cons:</p><ul><li>Verified Mark Certificate (VMC)</li><li>Common Mark Certificate (CMC)</li></ul><p>In essence, CMCs are cheaper and also allow for some slight variation, e.g. if your Logo changes color depending on season. On the other hand, VMCs don&#39;t offer this kind of flexibility, but some clients will display a &quot;verified&quot; checkmark next to your mail.</p><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><blockquote><p>It’s not DNS<br> There’s no way it’s DNS<br> It was DNS... and SVG.</p></blockquote><h3 id="dns-setup" tabindex="-1">DNS setup <a class="header-anchor" href="#dns-setup" aria-label="Permalink to &quot;DNS setup&quot;">​</a></h3><p>BIMI records are just TXT records. Our record, <code>default._bimi.syslifters.com</code>, looks like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; dig default._bimi.syslifters.com TXT +short</span></span>
<span class="line"><span>&quot;v=BIMI1;l=https://handbook.syslifters.com/assets/syslifters-bimi.svg&quot;</span></span></code></pre></div><p>This <code>default._bimi...</code> record contains two, optionally three, tags:</p><ul><li><code>v=</code>: This is the BIMI version, which is always <code>BIMI1</code></li><li><code>l=</code>: Defines the SVG location, in our case <a href="https://handbook.syslifters.com/assets/syslifters-bimi.svg" target="_blank" rel="noreferrer">https://handbook.syslifters.com/assets/syslifters-bimi.svg</a></li><li><code>a=</code>: This tag is <em>optional</em> and if set, links to the certificate (e.g. <code>https://example.com/cmc.pem</code>). Since we don&#39;t have one, there is no need for it.</li></ul><p>Not only do we have to configure BIMI, but we also need a strong (and enforced) DMARC policy. You can read more about the implementation on <a href="https://bimigroup.org/implementation-guide/" target="_blank" rel="noreferrer">bimigroup&#39;s implementation guide</a>, but in essence:</p><ul><li>a good policy is always a reject policy (<code>p=reject; sp=reject</code>)</li><li>BIMI validators won&#39;t accept: <code>p=none</code> policies or <code>pct</code> less than 100</li></ul><h3 id="svg-requirements" tabindex="-1">SVG requirements <a class="header-anchor" href="#svg-requirements" aria-label="Permalink to &quot;SVG requirements&quot;">​</a></h3><p>If DNS wasn&#39;t enough, we also need to adhere to SVG rules. Because BIMI images are based on the <code>tiny-ps</code> profile, we should:</p><ul><li>not use <code>&lt;g&gt;</code> group tags</li><li><code>style=&quot;&quot;</code> are unsupported</li><li><code>x=</code> or <code>y=</code> attributes are not permitted in the <code>&lt;svg&gt;</code> root tag</li><li>No animations or scripts (yes, the <code>tiny-ps</code> profile does not allow scripts, but feel free to experiment with XSS 😉</li></ul><p>Other than that, the SVG also must include a <code>&lt;title&gt;</code> tag (and optionally <code>&lt;description&gt;</code>) and it should use a solid background, because otherwise clients may display the image incorrectly (looking at you, dark and light mode). Lastly, they also must be publicly accessible (duh).</p><p>There is also a <a href="https://checkbimi.com/convertsvg" target="_blank" rel="noreferrer">BIMI image fixer</a> to automagically convert your SVGs into the valid BIMI format.</p><h4 id="our-bimi-ready-logos" tabindex="-1">Our BIMI-ready logos <a class="header-anchor" href="#our-bimi-ready-logos" aria-label="Permalink to &quot;Our BIMI-ready logos&quot;">​</a></h4><p>When preparing our logo, we tried to optimize it for both round and rectangular display options, hence it is slightly off-center to keep a somewhat even distance to the circle&#39;s edge.</p><h2 id="optional-certificates-cmc-vmc" tabindex="-1">Optional: Certificates (CMC / VMC) <a class="header-anchor" href="#optional-certificates-cmc-vmc" aria-label="Permalink to &quot;Optional: Certificates (CMC / VMC)&quot;">​</a></h2><p>VMC and CMC are &quot;mark certificates&quot; to prove image ownership (read trademark). If you are interested, here is <a href="https://bimigroup.org/resources/VMC_Requirements_latest.pdf" target="_blank" rel="noreferrer">bimigroup&#39;s VMC requirements (PDF)</a> (<a href="https://web.archive.org/web/20260311135702/https://bimigroup.org/resources/VMC_Requirements_latest.pdf" target="_blank" rel="noreferrer">alternative wayback link</a>):</p><table tabindex="0"><thead><tr><th style="text-align:right;">-</th><th>CMC</th><th>VMC</th></tr></thead><tbody><tr><td style="text-align:right;">Cost</td><td>Cheaper</td><td>More expensive</td></tr><tr><td style="text-align:right;">Slight changes to image (e.g. color)</td><td>Yes</td><td>No</td></tr><tr><td style="text-align:right;">&quot;Verified&quot; checkmark in Gmail</td><td>No</td><td>Yes</td></tr></tbody></table><h3 id="client-support-overview-as-of-2026-03" tabindex="-1">Client support overview (as of 2026-03) <a class="header-anchor" href="#client-support-overview-as-of-2026-03" aria-label="Permalink to &quot;Client support overview (as of 2026-03)&quot;">​</a></h3><p>Some mail providers will only show your image, if you are in possession of either a CMC or VMC for your brand image. We have listed some supported providers. Interestingly, Outlook apparently does not support BIMI as a receiving entity (original source: <a href="https://bimicertifications.com/insights/email-client-support-for-bimi" target="_blank" rel="noreferrer">BIMI client support overview</a>).</p><table tabindex="0"><thead><tr><th style="text-align:right;">Provider</th><th>Requirements</th></tr></thead><tbody><tr><td style="text-align:right;">Apple Mail</td><td>VMC</td></tr><tr><td style="text-align:right;">Google</td><td>CMC (VMCs add an additional &quot;verified&quot; checkmark)</td></tr><tr><td style="text-align:right;">Fastmail</td><td>DMARC</td></tr><tr><td style="text-align:right;">GMX / web.de</td><td>?</td></tr><tr><td style="text-align:right;">La Poste</td><td>DMARC</td></tr><tr><td style="text-align:right;">Yahoo</td><td>DMARC</td></tr></tbody></table>`,27)])])}const u=t(r,[["render",s]]);export{m as __pageData,u as default};
